<div class="toast-box"><div class="toast" id="toast"></div></div>

<script>
(function () {
'use strict';

/* ===== TEMA ===== */
var THEME_KEY = 'yoru_theme';

window.setTheme = function (id) {
  document.documentElement.setAttribute('data-theme', id === 'dark' ? '' : id);
  document.querySelectorAll('.theme-chip').forEach(function (c) {
    c.classList.toggle('active', c.getAttribute('data-theme-id') === id);
  });
  try { localStorage.setItem(THEME_KEY, id); } catch(e) {}
  /* Tenta salvar via bridge Android também (SharedPreferences) */
  try { if (window.Android && typeof Android.saveTheme === 'function') Android.saveTheme(id); } catch(e) {}
};

function loadTheme() {
  var saved = null;
  /* 1: tenta pegar do Android bridge */
  try { if (window.Android && typeof Android.getSavedTheme === 'function') saved = Android.getSavedTheme(); } catch(e) {}
  /* 2: fallback localStorage */
  if (!saved) { try { saved = localStorage.getItem(THEME_KEY); } catch(e) {} }
  if (saved && saved !== 'dark') setTheme(saved);
  else {
    /* marca chip dark como ativo por padrão */
    document.querySelectorAll('.theme-chip').forEach(function(c){
      c.classList.toggle('active', c.getAttribute('data-theme-id') === 'dark');
    });
  }
}

/* ===== BRIDGE ===== */
var A = {
  call: function (m, arg) {
    try { if (window.Android && typeof window.Android[m] === 'function') return arg !== undefined ? window.Android[m](arg) : window.Android[m](); } catch (e) { console.warn('Bridge.'+m, e); }
    return null;
  },
  parse: function (raw, fb) { try { return JSON.parse(raw) || fb; } catch(e) { return fb; } },
  connect:             function()    { A.call('connect'); },
  getStatus:           function()    { return A.call('getStatus') || 'DESCONECTADO'; },
  getServers:          function()    { return A.parse(A.call('getServers'),[]); },
  getSelected:         function()    { return A.parse(A.call('getSelectedServer'),{}); },
  selectServer:        function(pos) { A.call('selectServer',pos); },
  getMultiServers:     function()    { return A.parse(A.call('getMultiServers'),[]); },
  getSelectedMulti:    function()    { return A.parse(A.call('getSelectedMultiServer'),{}); },
  selectMultiServer:   function(pos) { A.call('selectMultiServer',pos); },
  getNote:             function()    { return A.call('getNote') || ''; },
  getVersion:          function()    { return A.call('getVersion') || ''; },
  getLogs:             function()    { return A.parse(A.call('getLogs'),[]); },
  clearLogs:           function()    { A.call('clearLogs'); },
  checkUpdate:         function()    { A.call('checkUpdate'); },
  requestInterstitial: function()    { A.call('requestInterstitial'); },
  isAdsEnabled:        function()    { return window.Android && typeof Android.isAdsEnabled==='function' ? Android.isAdsEnabled() : false; },
  getTimeLeft:         function()    { return window.Android && typeof Android.getTimeLeft==='function' ? Android.getTimeLeft() : 0; },
  watchAd:             function()    { A.call('watchAd'); },
  getSettings:         function()    { return A.parse(A.call('getSettings'), {}); },
  saveSettings:        function(obj) { try { if(window.Android && typeof Android.saveSettings==='function') Android.saveSettings(JSON.stringify(obj)); } catch(e){} }
};

var STATE = {
  CONECTADO:    { cls:'st-conectado',  label:'Protegido',        sub:'Sua conexão está 100% segura e privada.' },
  DESCONECTADO: { cls:'',              label:'Desprotegido',     sub:'Toque no escudo para iniciar a VPN.' },
  INICIANDO:    { cls:'st-conectando', label:'Iniciando...',     sub:'Preparando motor de conexão...' },
  PARANDO:      { cls:'st-conectando', label:'Parando...',       sub:'Encerrando túnel seguro...' },
  CONECTANDO:   { cls:'st-conectando', label:'Conectando...',    sub:'Estabelecendo rota segura...' },
  AGUARDANDO:   { cls:'st-conectando', label:'Aguardando...',    sub:'Negociando com o servidor...' },
  AUTENTICANDO: { cls:'st-conectando', label:'Autenticando...', sub:'Validando suas credenciais...' },
  RECONECTANDO: { cls:'st-conectando', label:'Reconectando...', sub:'Restaurando sinal perdido...' },
  NOPROCESS:    { cls:'',              label:'Desprotegido',     sub:'Toque no escudo para iniciar a VPN.' },
  ERRO:         { cls:'st-erro',       label:'Falha na conexão', sub:'Verifique sua internet ou credenciais.' }
};

var ALL_STATE_CLASSES = ['st-conectado','st-conectando','st-desconectado','st-erro'];
var app = { rawState:'NOPROCESS', connected:false, busy:false, startedAt:0, timerHandle:null, pollHandle:null };

function $(id) { return document.getElementById(id); }
function setText(id,v) { var el=$(id); if(el) el.textContent=String(v==null?'':v); }
function pad(n) { return String(n).padStart(2,'0'); }
function esc(s) { return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;'); }

function toast(msg, kind) {
  var el=$('toast'); if(!el) return;
  el.innerHTML=(kind==='ok'?'✅ ':kind==='err'?'❌ ':'⚠️ ')+msg;
  el.className='toast show '+(kind?kind:'');
  clearTimeout(el._t);
  el._t=setTimeout(function(){ el.className='toast'; },3000);
}

window.showPage = function(name) {
  document.querySelectorAll('.page').forEach(function(p){ p.classList.remove('active'); });
  document.querySelectorAll('.nav-btn').forEach(function(b){ b.classList.remove('active'); });
  var pg=$('page-'+name); if(pg) pg.classList.add('active');
  var nb=$('nav-'+name); if(nb) nb.classList.add('active');
  if(name==='servers') buildServerListPage();
};

function applyState(raw, detail) {
  raw=String(raw||'NOPROCESS').toUpperCase().trim();
  app.rawState=raw;
  var s=STATE[raw]||STATE['NOPROCESS'];
  ALL_STATE_CLASSES.forEach(function(c){ document.body.classList.remove(c); });
  if(s.cls) document.body.classList.add(s.cls);
  setText('status-label',s.label);
  setText('status-detail',detail||s.sub);
  setText('speed-status-label',s.label);
  app.connected=(raw==='CONECTADO');
  app.busy=['INICIANDO','CONECTANDO','AUTENTICANDO','AGUARDANDO','RECONECTANDO','PARANDO'].indexOf(raw)>=0;
  if(app.connected && !app.startedAt){ app.startedAt=Date.now(); startTimer(); }
  if(!app.connected && !app.busy){
    if(app.startedAt){ app.startedAt=0; stopTimer(); setText('timer-val','00:00'); }
    var tb=$('timer-bar'); if(tb) tb.classList.remove('show');
  }
}

function startTimer() {
  stopTimer();
  var tb=$('timer-bar'); if(tb) tb.classList.add('show');
  app.timerHandle=setInterval(function(){
    var sec=Math.floor((Date.now()-app.startedAt)/1000);
    var h=Math.floor(sec/3600),m=Math.floor((sec%3600)/60),s=sec%60;
    setText('timer-val',(h?pad(h)+':':'')+pad(m)+':'+pad(s));
  },1000);
}
function stopTimer(){ if(app.timerHandle){ clearInterval(app.timerHandle); app.timerHandle=null; } }

function startPolling(){
  app.pollHandle=setInterval(function(){
    var raw=A.getStatus();
    if(raw!==app.rawState) applyState(raw);
  },1200);
}

function renderLogs(){
  var container=$('log-container'); if(!container) return;
  var logs=A.getLogs();
  if(!logs||!logs.length){ container.innerHTML='<div style="color:var(--text-muted);padding:8px">Nenhum log ainda.</div>'; return; }
  var html='';
  for(var i=logs.length-1;i>=0;i--){
    var item=logs[i], level=String(item.level||'INFO').toUpperCase(), time=item.time?formatLogTime(item.time):'';
    html+='<div class="log-entry '+level+'"><span class="log-time">['+esc(time)+']</span> <span>'+esc(item.message||'')+'</span></div>';
  }
  container.innerHTML=html;
}

function formatLogTime(ms){ var d=new Date(ms); return pad(d.getHours())+':'+pad(d.getMinutes())+':'+pad(d.getSeconds()); }

function loadSavedCredentials(){
  try{
    var raw=window.Android&&window.Android.getSavedCredentials?window.Android.getSavedCredentials():'{}';
    var creds=JSON.parse(raw);
    var fUser=$('ci-ssh-user'),fPass=$('ci-ssh-pass'),fUdp=$('ci-udp-token'),fV2=$('ci-Xray-uuid');
    if(fUser) fUser.value=creds.sshUser||'';
    if(fPass) fPass.value=creds.sshPass||'';
    if(fUdp)  fUdp.value=creds.udpToken||'';
    if(fV2)   fV2.value=creds.xrayId||'';
  } catch(e){ console.warn('Creds:',e); }
}

function refreshInfo(){
  var ver=A.getVersion(); if(ver) setText('config-version',ver);
  var note=A.getNote();
  var mc=$('message-card'); if(mc){ mc.classList.toggle('show',!!note); setText('message-text',note); }
}

function refreshSelected(){
  var s=A.getSelected();
  if(s&&s.Name){
    setText('server-title',s.Name||'Servidor Automático');
    setText('server-sub',s.Info||'Pronto para uso');
    var wrap=$('server-flag-wrap');
    if(wrap&&(s.FlagUrl||s.Flag)){
      var src=s.FlagUrl?s.FlagUrl:'file:///android_asset/flags/'+s.Flag+'.png';
      wrap.innerHTML='<img src="'+esc(src)+'" onerror="this.parentElement.innerHTML=\'🌍\'">';
    }
  }
  var p=A.getSelectedMulti(), pCard=$('select-premium');
  if(p&&p.Name){
    if(pCard) pCard.style.display='flex';
    setText('premium-title',p.Name||'Selecionar Servidor');
    setText('premium-sub',p.Info||'Acesso VIP');
    var pwrap=$('premium-flag-wrap');
    if(pwrap&&(p.FlagUrl||p.Flag)){
      var psrc=p.FlagUrl?p.FlagUrl:'file:///android_asset/flags/'+p.Flag+'.png';
      pwrap.innerHTML='<img src="'+esc(psrc)+'" onerror="this.parentElement.innerHTML=\'💎\'">';
    }
  } else { if(pCard) pCard.style.display='none'; }
}

function buildServerList(type){
  var root=$('list-servers'); if(!root) return;
  root.innerHTML='';
  var isPremium=(type==='premium');
  var servers=isPremium?A.getMultiServers():A.getServers();
  var selected=isPremium?A.getSelectedMulti():A.getSelected();
  var selPos=selected?selected.position:-1;
  var mTitle=document.querySelector('#modal-servers .modal-title');
  if(mTitle) mTitle.textContent=isPremium?'Redes Premium':'Redes Livres';
  if(!servers||!servers.length){ root.innerHTML='<div style="color:var(--text-muted);padding:20px;text-align:center;">Lista vazia.</div>'; return; }
  servers.forEach(function(s,i){
    var isSel=(s.position===selPos||i===selPos);
    var flagSrc=s.FlagUrl?s.FlagUrl:(s.Flag?'file:///android_asset/flags/'+s.Flag+'.png':'');
    var el=document.createElement('div');
    el.className='list-item'+(isSel?' selected':'');
    el.innerHTML='<div class="li-icon">'+(flagSrc?'<img src="'+esc(flagSrc)+'" onerror="this.parentElement.innerHTML=\''+(isPremium?'💎':'🌍')+'\'">':(isPremium?'💎':'🌍'))+'</div>'+
      '<div class="li-main"><div class="li-title">'+esc(s.Name||'Rede')+'</div><div class="li-sub">'+esc(s.Info||(isPremium?'VIP':'Direct'))+'</div></div>'+
      '<span class="li-check">✓</span>';
    el.onclick=function(){
      if(app.connected){ toast('Desconecte para trocar de rede.','err'); return; }
      isPremium?A.selectMultiServer(s.position!==undefined?s.position:i):A.selectServer(s.position!==undefined?s.position:i);
      closeModal(); setTimeout(function(){ refreshSelected(); },250);
      toast(isPremium?'Rede VIP ativada!':'Rede selecionada!','ok');
    };
    root.appendChild(el);
  });
}

function buildServerListPage(){
  var root=$('list-servers-page'); if(!root) return;
  root.innerHTML='';
  var servers=A.getServers(), selected=A.getSelected(), selPos=selected?selected.position:-1;
  if(!servers||!servers.length){ root.innerHTML='<div style="color:var(--text-muted);text-align:center;padding:40px;">Lista indisponível.</div>'; return; }
  servers.forEach(function(s,i){
    var isSel=(s.position===selPos||i===selPos);
    var flagSrc=s.FlagUrl?s.FlagUrl:(s.Flag?'file:///android_asset/flags/'+s.Flag+'.png':'');
    var el=document.createElement('div');
    el.className='list-item'+(isSel?' selected':'');
    el.innerHTML='<div class="li-icon">'+(flagSrc?'<img src="'+esc(flagSrc)+'" onerror="this.parentElement.innerHTML=\'🌍\'">'  :'🌍')+'</div>'+
      '<div class="li-main"><div class="li-title">'+esc(s.Name||'Rede')+'</div><div class="li-sub">'+esc(s.Info||'Direct')+'</div></div>'+
      '<span class="li-check">✓</span>';
    el.onclick=function(){
      if(app.connected){ toast('Desconecte antes de alterar.','err'); return; }
      A.selectServer(s.position!==undefined?s.position:i);
      setTimeout(function(){ refreshSelected(); buildServerListPage(); },250);
      toast('Rede alterada.','ok');
    };
    root.appendChild(el);
  });
}

window.openModal=function(id){
  $('modal-mask').classList.add('show');
  document.querySelectorAll('.modal-box').forEach(function(b){ b.classList.remove('active'); });
  var box=$(id); if(box) box.classList.add('active');
};
window.closeModal=function(){
  $('modal-mask').classList.remove('show');
  document.querySelectorAll('.modal-box').forEach(function(b){ b.classList.remove('active'); });
};
function openCredsModal(){ loadSavedCredentials(); openModal('modal-creds'); }

/* Tempo restante */
var MAX_FREE_MS=999999999, timeCard,timeFillEl,timeValEl,timeHandle,baseTimeMs=0;
function initTimeCard(){
  timeCard=$('time-card'); timeFillEl=$('time-bar-fill'); timeValEl=$('time-remaining-val');
  var adsOn=A.isAdsEnabled(), left=A.getTimeLeft();
  if(!adsOn||left>=MAX_FREE_MS){ if(timeCard) timeCard.classList.remove('show'); return; }
  if(timeCard) timeCard.classList.add('show');
  baseTimeMs=7200000; updateTimeDisplay(left); startTimeCountdown(left);
}
function startTimeCountdown(ms){
  if(timeHandle) clearInterval(timeHandle);
  var remaining=ms;
  timeHandle=setInterval(function(){
    remaining-=1000;
    if(remaining<=0){ remaining=0; clearInterval(timeHandle); if(app.connected) A.connect(); updateTimeDisplay(0); toast('Sessão expirada. Assista a um anúncio.','warn'); }
    updateTimeDisplay(remaining);
  },1000);
}
function updateTimeDisplay(ms){
  if(!timeValEl) return;
  if(ms<=0){ timeValEl.textContent='00:00'; if(timeFillEl) timeFillEl.style.width='0%'; return; }
  var totalSec=Math.floor(ms/1000),h=Math.floor(totalSec/3600),m=Math.floor((totalSec%3600)/60),s=totalSec%60;
  timeValEl.textContent=(h?pad(h)+':':'')+pad(m)+':'+pad(s);
  if(timeFillEl){
    var pct=Math.min(100,(ms/baseTimeMs)*100);
    timeFillEl.style.width=pct+'%';
    timeFillEl.style.background=pct<20?'linear-gradient(90deg,#ef4444,#f59e0b)':'linear-gradient(90deg,#f59e0b,#ea580c)';
  }
}

/* Sync speed */
setInterval(function(){
  var dl=$('speed-dl'),dlB=$('speed-dl-big'); if(dl&&dlB&&dl.textContent!==dlB.textContent) dlB.textContent=dl.textContent;
  var ul=$('speed-ul'),ulB=$('speed-ul-big'); if(ul&&ulB&&ul.textContent!==ulB.textContent) ulB.textContent=ul.textContent;
},1000);

/* Callbacks Android */
window.onVpnStatus        = function(raw,detail){ applyState(raw,detail||''); };
window.onShowInterstitial = function(){ A.requestInterstitial(); };
window.onCheckUserReceived = function(data){
  var card=$('checkuser-card'); if(!card) return;
  card.classList.add('show');
  var u=typeof data==='string'?JSON.parse(data):data;
  setText('cu-username',u.username||'—');
  setText('cu-connections',(u.count_connection||'—')+' / '+(u.limiter_user||'—'));
  setText('cu-expiration',u.expiration_date||'—');
  setText('cu-days',(u.expiration_days||'—')+' dias ativos');
};
window.onLogAdded=function(itemJson){
  var container=$('log-container'); if(!container) return;
  try{
    var item=typeof itemJson==='string'?JSON.parse(itemJson):itemJson;
    var level=String(item.level||'INFO').toUpperCase();
    var div=document.createElement('div');
    div.className='log-entry '+level;
    div.innerHTML='<span class="log-time">['+esc(formatLogTime(item.time||Date.now()))+']</span> <span>'+esc(item.message||'')+'</span>';
    container.insertBefore(div,container.firstChild);
  } catch(e){}
};
window.onLogsCleared   = function(){ var c=$('log-container'); if(c) c.innerHTML=''; };
window.onServerChanged = function(){ refreshSelected(); var pg=$('page-servers'); if(pg&&pg.classList.contains('active')) buildServerListPage(); };
window.onConfigUpdated = function(){ refreshInfo(); refreshSelected(); toast('Dados sincronizados!','ok'); };
window.onAdLoading     = function(){ var btn=$('btn-watch-ad'); if(btn){ btn.textContent='Carregando...'; btn.disabled=true; } };
window.onTimeAdded     = function(newTotalMs){
  if(timeHandle) clearInterval(timeHandle);
  updateTimeDisplay(newTotalMs); startTimeCountdown(newTotalMs);
  baseTimeMs=Math.max(baseTimeMs,7200000);
  var btn=$('btn-watch-ad'); if(btn){ btn.textContent='Assistir Anúncio (+2 Horas)'; btn.disabled=false; }
  toast('+2 Horas concedidas!','ok');
};
window.onAdFailed=function(){
  var btn=$('btn-watch-ad'); if(btn){ btn.textContent='Assistir Anúncio (+2 Horas)'; btn.disabled=false; }
  toast('Anúncio falhou.','err');
};

window.toggleCiPass=function(id){ var f=$(id); if(!f) return; f.type=f.type==='password'?'text':'password'; };

function loadSettings() {
  var s = A.getSettings();
  function setChk(id, val) { var el = $(id); if (el) el.checked = !!val; }
  function setVal(id, val) { var el = $(id); if (el && val !== undefined && val !== null) el.value = val; }
  function setSel(id, val) { var el = $(id); if (el && val) el.value = val; }
  setChk('cfg-dns-forward',      s.dnsForward !== undefined ? s.dnsForward : true);
  setVal('cfg-dns1',             s.dnsResolver  || '1.1.1.1');
  setVal('cfg-dns2',             s.dnsResolver2 || '1.0.0.1');
  setSel('cfg-ip-version',       s.ipVersion    || 'auto');
  setSel('cfg-tls-version',      s.tlsVersion   || 'auto');
  setChk('cfg-udp-forward',      s.udpForward !== undefined ? s.udpForward : false);
  setVal('cfg-udp-resolver',     s.udpResolver  || '127.0.0.1:7300');
  setVal('cfg-pinger',           s.pinger !== undefined ? s.pinger : 3);
  setChk('cfg-adaptive',         s.adaptiveConnector !== undefined ? s.adaptiveConnector : true);
  setChk('cfg-ssh-compression',  s.sshCompression || false);
  setChk('cfg-no-delay',         s.disableDelay   || false);
  setChk('cfg-wakelock',         s.cpuWakeLock    || false);
  setChk('cfg-debug',            s.modeDebug      || false);
  setChk('cfg-auto-clear',       s.autoClearLogs !== undefined ? s.autoClearLogs : true);
  setChk('cfg-vibrate',          s.vibrate !== undefined ? s.vibrate : true);
  updateDepRows();
}

function updateDepRows() {
  var dnsOn = ($('cfg-dns-forward') || {}).checked;
  document.querySelectorAll('.dep-dns').forEach(function(r) {
    r.style.opacity = dnsOn ? '1' : '0.35';
    var inp = r.querySelector('input'); if (inp) inp.disabled = !dnsOn;
  });
  var udpOn = ($('cfg-udp-forward') || {}).checked;
  document.querySelectorAll('.dep-udp').forEach(function(r) {
    r.style.opacity = udpOn ? '1' : '0.35';
    var inp = r.querySelector('input'); if (inp) inp.disabled = !udpOn;
  });
}

function saveSettings() {
  function chk(id) { var el = $(id); return el ? el.checked : false; }
  function val(id) { var el = $(id); return el ? el.value.trim() : ''; }
  var obj = {
    dnsForward:        chk('cfg-dns-forward'),
    dnsResolver:       val('cfg-dns1')        || '1.1.1.1',
    dnsResolver2:      val('cfg-dns2')        || '1.0.0.1',
    ipVersion:         val('cfg-ip-version')  || 'auto',
    tlsVersion:        val('cfg-tls-version') || 'auto',
    udpForward:        chk('cfg-udp-forward'),
    udpResolver:       val('cfg-udp-resolver')|| '127.0.0.1:7300',
    pinger:            parseInt(val('cfg-pinger')) || 3,
    adaptiveConnector: chk('cfg-adaptive'),
    sshCompression:    chk('cfg-ssh-compression'),
    disableDelay:      chk('cfg-no-delay'),
    cpuWakeLock:       chk('cfg-wakelock'),
    modeDebug:         chk('cfg-debug'),
    autoClearLogs:     chk('cfg-auto-clear'),
    vibrate:           chk('cfg-vibrate')
  };
  A.saveSettings(obj);
  toast('Configurações salvas!', 'ok');
}

function bind(){
  var btnConn=$('btn-connect');
  if(btnConn) btnConn.onclick=function(){
    var raw=app.rawState; if(raw==='PARANDO') return;
    A.connect();
    if(raw==='CONECTADO') applyState('PARANDO','Encerrando túnel...');
    else if(['INICIANDO','CONECTANDO','AUTENTICANDO','AGUARDANDO','RECONECTANDO'].indexOf(raw)<0) applyState('INICIANDO','Preparando conexão...');
  };

  var sServ=$('select-server');  if(sServ)  sServ.onclick=function(){ buildServerList('normal');  openModal('modal-servers'); };
  var pCard=$('select-premium'); if(pCard)  pCard.onclick=function(){ buildServerList('premium'); openModal('modal-servers'); };

  var tCred=$('tool-creds');  if(tCred)  tCred.onclick=function(){ openCredsModal(); };
  var tUpd=$('tool-update');  if(tUpd)   tUpd.onclick=function(){ toast('Sincronizando...',''); A.checkUpdate(); };
  var tLog=$('tool-logs');    if(tLog)   tLog.onclick=function(){ renderLogs(); openModal('modal-logs'); };

  var cSave=$('btn-creds-save');
  if(cSave) cSave.onclick=function(){
    var u=($('ci-ssh-user')||{}).value||'', p=($('ci-ssh-pass')||{}).value||'';
    var udp=($('ci-udp-token')||{}).value||'', v2=($('ci-Xray-uuid')||{}).value||'';
    if(window.Android&&typeof window.Android.saveCredentials==='function'){
      window.Android.saveCredentials(u,p,udp,v2); closeModal(); toast('Dados salvos.','ok');
    } else { toast('Erro de comunicação.','err'); }
  };

  var rLog=$('btn-refresh-logs'); if(rLog) rLog.onclick=function(){ renderLogs(); };
  var cLog=$('btn-clear-logs');   if(cLog) cLog.onclick=function(){ A.clearLogs(); var c=$('log-container'); if(c) c.innerHTML='<div style="color:var(--text-muted);padding:8px">Limpo.</div>'; toast('Cache limpo.',''); };

  var dnsToggle = $('cfg-dns-forward');
  if (dnsToggle) dnsToggle.onchange = updateDepRows;

  var udpToggle = $('cfg-udp-forward');
  if (udpToggle) udpToggle.onchange = updateDepRows;

  var btnSaveSettings = $('btn-settings-save');
  if (btnSaveSettings) btnSaveSettings.onclick = saveSettings;

  document.querySelectorAll('.modal-close').forEach(function(b){ b.onclick=closeModal; });
  var mMask=$('modal-mask'); if(mMask) mMask.onclick=function(e){ if(e.target===mMask) closeModal(); };

  var btnAd=$('btn-watch-ad');
  if(btnAd) btnAd.onclick=function(){ btnAd.textContent='Aguarde...'; btnAd.disabled=true; A.watchAd(); };
}

function boot(){
  loadTheme();
  bind();
  initTimeCard();
  refreshInfo();
  refreshSelected();
  applyState(A.getStatus());
  startPolling();
  setInterval(refreshInfo,15000);
  loadSettings();
}

if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',boot);
else boot();

})();
</script>

<style id="yoru-fx-styles">
  /* 1. Wallpaper do Menino Pescando (Quase invisível) */
  .fishing-boy-bg {
    position: fixed;
    inset: 0;
    z-index: -1;
    pointer-events: none;
    background-image: url('https://images.unsplash.com/photo-1506126613408-eca07ce68773?auto=format&fit=crop&w=1000&q=80');
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    opacity: 0.04; /* Quase invisível */
    mix-blend-mode: screen;
  }

  /* 2. Sol e Lua flutuando */
  .celestial-body {
    position: fixed;
    top: 30px;
    right: 30px;
    font-size: 50px;
    z-index: 1;
    pointer-events: none;
    animation: floatCelestial 6s ease-in-out infinite alternate;
  }

  /* Controle do Sol: Forte no claro, fraco no escuro */
  .celestial-sun { opacity: 0.3; filter: drop-shadow(0 0 10px rgba(255, 200, 0, 0.2)); }
  [data-theme="light"] .celestial-sun { opacity: 1; filter: drop-shadow(0 0 20px rgba(255, 200, 0, 0.8)); }
  .celestial-moon { filter: drop-shadow(0 0 15px rgba(255, 255, 255, 0.5)); }

  @keyframes floatCelestial {
    0% { transform: translateY(0px) rotate(-5deg); }
    100% { transform: translateY(15px) rotate(5deg); }
  }

  /* 3. Bola de Futebol Aleatória */
  .random-football {
    position: fixed;
    font-size: 24px;
    z-index: 100;
    pointer-events: none; /* Não atrapalha o clique na VPN */
    user-select: none;
  }

  /* 4. Estrelas de Fundo */
  .fx-star {
    position: fixed;
    background-color: #fff;
    border-radius: 50%;
    pointer-events: none;
    z-index: 0;
    opacity: 0;
    animation: twinkleStar linear infinite;
  }
  [data-theme="light"] .fx-star { background-color: #0f172a; opacity: 0; } /* Estrelas escuras no tema claro */

  @keyframes twinkleStar {
    0% { opacity: 0; transform: scale(0.5); }
    50% { opacity: 0.6; transform: scale(1); }
    100% { opacity: 0; transform: scale(0.5); }
  }
</style>

<script id="yoru-fx-script">
(function() {
  // 1. Injetar Wallpaper
  const bg = document.createElement('div');
  bg.className = 'fishing-boy-bg';
  document.body.appendChild(bg);

  // 2. Lógica do Sol e Lua
  const hour = new Date().getHours();
  const isDay = hour >= 6 && hour < 18; // Entre 6h e 17h59 é dia
  const celestial = document.createElement('div');
  celestial.className = 'celestial-body ' + (isDay ? 'celestial-sun' : 'celestial-moon');
  celestial.innerText = isDay ? '☀️' : '🌙';
  document.body.appendChild(celestial);

  // 3. Estrelinhas no Fundo (Apenas 30 para não travar o celular)
  const createStars = () => {
    for (let i = 0; i < 30; i++) {
      let star = document.createElement('div');
      let size = Math.random() * 3 + 1; // 1px a 4px
      star.className = 'fx-star';
      star.style.width = size + 'px';
      star.style.height = size + 'px';
      star.style.left = Math.random() * 100 + 'vw';
      star.style.top = Math.random() * 100 + 'vh';
      star.style.animationDuration = (Math.random() * 3 + 2) + 's';
      star.style.animationDelay = Math.random() * 2 + 's';
      document.body.appendChild(star);
    }
  };
  createStars();

  // 4. A Bola de Futebol Quicando pela Tela (Física Simples)
  const ball = document.createElement('div');
  ball.className = 'random-football';
  ball.innerText = '⚽';
  document.body.appendChild(ball);

  let ballX = Math.random() * window.innerWidth;
  let ballY = Math.random() * window.innerHeight;
  let velX = 2; // Velocidade Horizontal
  let velY = 2; // Velocidade Vertical
  let rotation = 0;

  function animateBall() {
    ballX += velX;
    ballY += velY;
    rotation += 3;

    // Colisão com as bordas da tela
    if (ballX + 30 >= window.innerWidth || ballX <= 0) velX = -velX;
    if (ballY + 30 >= window.innerHeight || ballY <= 0) velY = -velY;

    ball.style.transform = `translate(${ballX}px, ${ballY}px) rotate(${rotation}deg)`;
    requestAnimationFrame(animateBall);
  }

  // Inicia a bola quicando
  animateBall();

})();
</script>




